svg.script:
(function () {
  /* prevent dark-mode first-paint flash before bootstrap */
  if (window.location.href.indexOf('theme=dark') !== -1) {
    document.documentElement.classList.add('dark');
  }
}());

(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var pie = svgEl.querySelector('#pie');
    var R   = 195, PUSH = 14;
    var FRAME_W = 1120, FRAME_H = 455;
    var CX = 416, CY = 228;

    function easeOutCubic(t) { return 1 - Math.pow(1-t, 3); }
    function easeOutBack(t)  { var c1=1.70158,c3=c1+1; return 1+c3*Math.pow(t-1,3)+c1*Math.pow(t-1,2); }

    var sliceEls = ctx.$$all('.slice-g');
    var SPIN_DUR = 550, STAGGER = 225, FADE_DUR = 800;
    var startTime = null;

    sliceEls.forEach(function (g) { g.style.opacity = '0'; });
    var holeEl = svgEl.querySelector('#hole-group');
    holeEl.style.opacity = '0';

    function animateSlices(ts) {
      if (!startTime) startTime = ts;
      var elapsed = ts - startTime;
      sliceEls.forEach(function (g, i) {
        var t     = Math.max(0, Math.min(1, (elapsed - i*STAGGER) / SPIN_DUR));
        var tFade = Math.max(0, Math.min(1, (elapsed - i*STAGGER) / FADE_DUR));
        var span  = parseFloat(g.getAttribute('data-span'));
        g.setAttribute('transform', 'rotate('+(easeOutBack(t)*span-span).toFixed(3)+')');
        g.style.opacity = easeOutCubic(tFade).toFixed(3);
      });
      var holeStart = (sliceEls.length-1)*STAGGER + SPIN_DUR*0.7;
      holeEl.style.opacity = easeOutCubic(Math.max(0, Math.min(1, (elapsed-holeStart)/300))).toFixed(3);
      var totalDur = (sliceEls.length-1)*STAGGER + SPIN_DUR + 300;
      if (elapsed < totalDur) {
        requestAnimationFrame(animateSlices);
      } else {
        sliceEls.forEach(function (g) { g.removeAttribute('transform'); g.style.opacity = ''; });
        holeEl.style.opacity = '1';
        pie.classList.add('ready');
      }
    }
    requestAnimationFrame(animateSlices);

    var tip    = svgEl.querySelector('#tip');
    var tipBg  = svgEl.querySelector('#tip-bg');
    var tipBdr = svgEl.querySelector('#tip-bdr');
    var tipArr = svgEl.querySelector('#tip-arr');
    var tipLbl = svgEl.querySelector('#tip-lbl');
    var tipSub = svgEl.querySelector('#tip-sub');
    var tipVal = svgEl.querySelector('#tip-val');
    var tipPct = svgEl.querySelector('#tip-pct');

    function showTip(g) {
      var midDeg = parseFloat(g.getAttribute('data-mid'));
      var label  = g.getAttribute('data-label');
      var val    = g.getAttribute('data-val');
      var pct    = g.getAttribute('data-pct');
      var midRad = midDeg * Math.PI / 180;
      var dx = Math.cos(midRad), dy = Math.sin(midRad);
      var ancX = CX + dx * (R + PUSH), ancY = CY + dy * (R + PUSH);

      ctx.layoutSideTooltip(tip, {
        anchorX: ancX,
        anchorY: ancY,
        plotL: 4,
        plotR: 800,
        plotT: 4,
        plotB: FRAME_H - 4,
        lines: [
          { text: val, className: 'tip-value' },
          { text: label + ' - ' + pct, className: 'tip-label' }
        ],
        lineHeights: [70, 62],
        minWidth: 260,
        paddingX: 20,
        paddingY: 24
      });
      ctx.setOpacity(tip, 1);
    }

    function hideTip() { ctx.setOpacity(tip, null); }

    ctx.initRadialHover(pie, sliceEls, {
      onActivate: function (g) {
        var midDeg = parseFloat(g.getAttribute('data-mid'));
        var midRad = midDeg * Math.PI / 180;
        var dx = Math.cos(midRad), dy = Math.sin(midRad);
        var pathEl = svgEl.querySelector('#sp' + g.id.replace('sl', ''));
        if (pathEl) pathEl.setAttribute('transform', 'translate('+(dx*PUSH).toFixed(1)+','+(dy*PUSH).toFixed(1)+')');
        showTip(g);
      },
      onDeactivate: function () {
        sliceEls.forEach(function (g) {
          var pathEl = svgEl.querySelector('#sp' + g.id.replace('sl', ''));
          if (pathEl) pathEl.removeAttribute('transform');
        });
        hideTip();
      }
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
